    "id": "1623326725_IniciaodePagamentosSemRedirecionamento-RegrasdeValidao_chunk_7_ef213faa",
    "text_content": "*''%/? #]+, retorna Invalido rejectionReasonCode SE Role = CLIENT E status = REJECTED E endpoint = %/enrollments/v x /enrollments/{enrollmentId} E método = PATCH ou GET E statusCode não é 4xx ou 5xx ENTÃO Se rejectionReasonCode for nulo, retorna Nulo Se rejectionReasonCode for vazio, retorna Vazio Se rejectionReasonCode não for REJEITADO_DISPOSITIVO_INCOMPATIVEL, REJEITADO_FALHA_FIDO, REJEITADO_FALHA_HYBRID_FLOW, REJEITADO_FALHA_INFRAESTRUTURA, REJEITADO_MANUALMENTE, REJEITADO_MAXIMO_CHALLENGES_ATINGIDO, REJEITADO_OUTRO, REJEITADO_SEGURANCA_INTERNA, REJEITADO_TEMPO_EXPIRADO_ACCOUNT_HOLDER_VALIDATION, REJEITADO_TEMPO_EXPIRADO_RISK_SIGNALS, REJEITADO_TEMPO_EXPIRADO_ENROLLMENT ou REJEITADO_TITULARIDADE_DIVERGENTE, retorna Invalido revocationReasonCode SE Role = CLIENT E status = REVOKED E endpoint = %/enrollments/v x /enrollments/{enrollmentId} E método = PATCH OU GET e statusCode = 200 ENTÃO Se revocationReasonCode for nulo, retorna Nulo Se revocationReasonCode for vazio, retorna Vazio Se revocationReasonCode não for REVOGADO_FALHA_INFRAESTRUTURA, REVOGADO_MANUALMENTE, REVOGADO_OUTRO, REVOGADO_SEGURANCA_INTERNA ou REVOGADO_VALIDADE_EXPIRADA, retorna Invalido rp SE Role = CLIENT E endpoint = %/enrollments/v x /enrollments/{enrollmentId}/fido-registration-options ou %/enrollments/v x /enrollments/{enrollmentId}/fido-sign-options E método = POST ENTÃO Se rpf or nulo, retorna Nulo Se rp for vazio, retorna Vazio status SE Role = CLIENT E endpoint = %/enrollments/v x /enrollments ou %/enrollments/v x /enrollments/{enrollmentId} E método = POST ou GET E statusCode = 2xx ENTÃO Se status for nulo, retorna Nulo Se status for vazio, retorna Vazio Se status não for AUTHORISED, REJECTED, REVOKED, AWAITING_RISK_SIGNALS, AWAITING_ACCOUNT_HOLDER_VALIDATION ou AWAITING_ENROLLMENT, retorna Invalido tokenId SE Role = CLIENT E endpoint = %/enrollments/v x /enrollments%, %/enrollments/v x /consents/{consentId}/authorise, %/enrollments/v x /recurring-consents/{recurringConsentId}/authorise E método = POST ou GET E statusCode = 2xx ENTÃO Se status for nulo, retorna Nulo Se status for vazio, retorna Vazio Se status não for AUTHORISED, REJECTED, REVOKED, AWAITING_RISK_SIGNALS, AWAITING_ACCOUNT_HOLDER_VALIDATION ou AWAITING_ENROLLMENT, retorna Invalido",
